create table billing_groups (
    billing_group_id varchar2(30 byte),
    customer_id      varchar2(36 byte),
    group_title      varchar2(255 byte),
    status           varchar2(20 byte),
    currency_code    varchar2(10 byte),
    created_at       date,
    created_by       varchar2(50 byte)
);


